namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Abbreviation { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public interface ICatalogService
{
    IReadOnlyList<Department> GetDepartments();
    IReadOnlyList<Course> GetCourses(string? searchTerm = null, int? departmentId = null);
    IReadOnlyList<Course> GetFeaturedCourses();
    Course? GetCourseById(int id);
    Department? GetDepartmentById(int id);
    void SubmitEnrollmentRequest(EnrollmentRequest request);
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService : ICatalogService
{
    private static readonly List<Department> Departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 4, Name = "English", Abbreviation = "ENG" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" },
    ];

    private static readonly List<Course> Courses =
    [
        new()
        {
            Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
            Description = "Learn the fundamentals of programming using C#. Topics include variables, control structures, methods, and object-oriented principles. No prior experience required.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. Sarah Chen",
            InstructorBio = "Dr. Chen has 15 years of experience teaching introductory CS courses and has published research on programming pedagogy."
        },
        new()
        {
            Id = 2, CourseCode = "CS 301", Title = "Data Structures and Algorithms",
            Description = "Study of fundamental data structures (trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy algorithms).",
            Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. James Park",
            InstructorBio = "Dr. Park specializes in algorithm optimization and has industry experience at major tech companies."
        },
        new()
        {
            Id = 3, CourseCode = "CS 450", Title = "Machine Learning",
            Description = "Introduction to machine learning concepts including supervised learning, unsupervised learning, neural networks, and model evaluation techniques.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, IsFeatured = false,
            InstructorName = "Dr. Maria Rodriguez",
            InstructorBio = "Dr. Rodriguez leads the university's AI research lab and has published over 40 papers in top ML conferences."
        },
        new()
        {
            Id = 4, CourseCode = "MATH 201", Title = "Linear Algebra",
            Description = "Study of vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of equations.",
            Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 2, IsFeatured = true,
            InstructorName = "Dr. Robert Kim",
            InstructorBio = "Dr. Kim is an award-winning educator known for making abstract mathematical concepts accessible to all students."
        },
        new()
        {
            Id = 5, CourseCode = "MATH 301", Title = "Differential Equations",
            Description = "First and second-order ODEs, systems of equations, Laplace transforms, series solutions, and applications in science and engineering.",
            Credits = 4, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, IsFeatured = false,
            InstructorName = "Dr. Emily Watson",
            InstructorBio = "Dr. Watson's research focuses on applied mathematics with emphasis on mathematical modeling in biology."
        },
        new()
        {
            Id = 6, CourseCode = "PHYS 101", Title = "General Physics I",
            Description = "Mechanics, thermodynamics, and waves. Calculus-based introduction to physics with laboratory component.",
            Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM + Lab Thu 2:00–4:50 PM", DepartmentId = 3, IsFeatured = true,
            InstructorName = "Dr. Alan Foster",
            InstructorBio = "Dr. Foster brings 20 years of research experience in experimental physics and is passionate about hands-on learning."
        },
        new()
        {
            Id = 7, CourseCode = "PHYS 320", Title = "Quantum Mechanics",
            Description = "Wave-particle duality, Schrödinger equation, quantum states, angular momentum, spin, and applications to atomic physics.",
            Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = 3, IsFeatured = false,
            InstructorName = "Dr. Lisa Nguyen",
            InstructorBio = "Dr. Nguyen is a theoretical physicist whose research explores quantum computing and quantum information theory."
        },
        new()
        {
            Id = 8, CourseCode = "ENG 201", Title = "Creative Writing",
            Description = "Workshop-based course exploring fiction, poetry, and creative nonfiction. Students develop their voice through regular writing exercises and peer critique.",
            Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Prof. David Hart",
            InstructorBio = "Prof. Hart is a published novelist and poet with three National Book Award nominations."
        },
        new()
        {
            Id = 9, CourseCode = "ENG 305", Title = "Shakespeare",
            Description = "In-depth study of Shakespeare's major plays including tragedies, comedies, and histories. Emphasis on close reading and historical context.",
            Credits = 3, Schedule = "Mon/Wed 10:00–11:20 AM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Dr. Catherine Mills",
            InstructorBio = "Dr. Mills is a Shakespeare scholar who has directed over 20 productions and published extensively on early modern theater."
        },
        new()
        {
            Id = 10, CourseCode = "HIST 101", Title = "World History to 1500",
            Description = "Survey of major civilizations, cultural developments, and global interactions from prehistory through the late medieval period.",
            Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 5, IsFeatured = false,
            InstructorName = "Dr. Michael Torres",
            InstructorBio = "Dr. Torres specializes in comparative world history and has conducted fieldwork across three continents."
        },
    ];

    public IReadOnlyList<Department> GetDepartments() => Departments;

    public IReadOnlyList<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = Courses.AsEnumerable();

        if (departmentId.HasValue)
        {
            query = query.Where(c => c.DepartmentId == departmentId.Value);
        }

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public IReadOnlyList<Course> GetFeaturedCourses() =>
        Courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourseById(int id) =>
        Courses.FirstOrDefault(c => c.Id == id);

    public Department? GetDepartmentById(int id) =>
        Departments.FirstOrDefault(d => d.Id == id);

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist to a database.
        // For now, we just validate and accept the request.
    }
}

