@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Browse Courses</PageTitle>

<h1>Browse Courses</h1>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-6">
        <label for="search" class="form-label">Search</label>
        <input type="text" class="form-control" id="search" name="search" value="@Search" placeholder="Search by title, code, or keyword..." />
    </div>
    <div class="col-md-4">
        <label for="departmentId" class="form-label">Department</label>
        <select class="form-select" id="departmentId" name="departmentId">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-end">
        <button type="submit" class="btn btn-primary w-100">Filter</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                var dept = CatalogService.GetDepartmentById(course.DepartmentId);
                <tr>
                    <td>@course.CourseCode</td>
                    <td>@course.Title</td>
                    <td>@dept?.Name</td>
                    <td>@course.Credits</td>
                    <td><a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private IReadOnlyList<Department> departments = [];
    private IReadOnlyList<Course> courses = [];

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        courses = CatalogService.GetCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <h1>Course Not Found</h1>
    <p>The requested course does not exist.</p>
    <a href="courses" class="btn btn-secondary">Back to Courses</a>
}
else
{
    <PageTitle>@course.CourseCode — @course.Title</PageTitle>

    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.CourseCode</li>
        </ol>
    </nav>

    <h1>@course.CourseCode: @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h2>Description</h2>
            <p>@course.Description</p>

            <h2 class="mt-4">Schedule</h2>
            <p><strong>@course.Schedule</strong></p>

            <h2 class="mt-4">Credits</h2>
            <p><span class="badge bg-info fs-6">@course.Credits credits</span></p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2">@course.InstructorName</h6>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? department;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourseById(Id);
        if (course is not null)
        {
            department = CatalogService.GetDepartmentById(course.DepartmentId);
        }
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Complete the form below to submit an enrollment request.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
        <hr />
        <a href="courses" class="btn btn-outline-success">Browse More Courses</a>
    </div>
}
else
{
    <form method="post" @formname="enrollment">
        <AntiforgeryToken />
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" name="Model.StudentName" value="@Model.StudentName" required />
                    @if (errors.ContainsKey(nameof(Model.StudentName)))
                    {
                        <div class="text-danger">@errors[nameof(Model.StudentName)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" name="Model.StudentId" value="@Model.StudentId" required />
                    @if (errors.ContainsKey(nameof(Model.StudentId)))
                    {
                        <div class="text-danger">@errors[nameof(Model.StudentId)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" name="Model.CourseId" required>
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode — @course.Title</option>
                        }
                    </select>
                    @if (errors.ContainsKey(nameof(Model.CourseId)))
                    {
                        <div class="text-danger">@errors[nameof(Model.CourseId)]</div>
                    }
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="courses" class="btn btn-secondary ms-2">Cancel</a>
            </div>
        </div>
    </form>
}

