@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject ICatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Complete the form below to submit an enrollment request.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseTitle</strong> has been received.</p>
        <hr />
        <a href="courses" class="btn btn-outline-success">Browse More Courses</a>
    </div>
}
else
{
    <EditForm method="post" Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment">
        <DataAnnotationsValidator />
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <InputText class="form-control" id="studentName" @bind-Value="Model.StudentName" />
                    <ValidationMessage For="() => Model.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <InputText class="form-control" id="studentId" @bind-Value="Model.StudentId" />
                    <ValidationMessage For="() => Model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <InputSelect class="form-select" id="courseId" @bind-Value="Model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id">@course.CourseCode — @course.Title</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
                <a href="courses" class="btn btn-secondary ms-2">Cancel</a>
            </div>
        </div>
    </EditForm>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private IReadOnlyList<Course> courses = [];
    private bool submitted;
    private string selectedCourseTitle = string.Empty;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();

        // Pre-select course if provided via query string and form hasn't been submitted
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        CatalogService.SubmitEnrollmentRequest(Model);
        var course = CatalogService.GetCourseById(Model.CourseId);
        selectedCourseTitle = course is not null ? $"{course.CourseCode} — {course.Title}" : "Unknown Course";
        submitted = true;
    }
}

