@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private IReadOnlyList<Course> courses = [];
    private bool submitted;
    private string selectedCourseTitle = string.Empty;
    private Dictionary<string, string> errors = new();

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();

        // Pre-select course if provided via query string
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }

        // Handle form POST
        if (HttpMethods.IsPost(HttpContextAccessor.HttpContext?.Request.Method ?? "GET"))
        {
            ValidateAndSubmit();
        }
    }

    [CascadingParameter] public HttpContext? HttpContextAccessor { get; set; }

    private void ValidateAndSubmit()
    {
        errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.StudentName))
            errors[nameof(Model.StudentName)] = "Name is required.";

        if (string.IsNullOrWhiteSpace(Model.StudentId))
            errors[nameof(Model.StudentId)] = "Student ID is required.";

        if (Model.CourseId < 1)
            errors[nameof(Model.CourseId)] = "Please select a course.";

        if (errors.Count == 0)
        {
            CatalogService.SubmitEnrollmentRequest(Model);
            var course = CatalogService.GetCourseById(Model.CourseId);
            selectedCourseTitle = course is not null ? $"{course.CourseCode} — {course.Title}" : "Unknown Course";
            submitted = true;
        }
    }
}

